# Iterator və generator müqayisəsi
# Iterator
class MyIterator:
    def __init__(self, max_num):
        self.max_num = max_num
        self.current = 0

    def __iter__(self):
        return self

    def __next__(self):
        if self.current < self.max_num:
            result = self.current
            self.current += 1
            return result
        raise StopIteration

# Generator
def my_generator(max_num):
    for i in range(max_num):
        yield i

iterator = MyIterator(3)
for num in iterator:
    print(f'Iterator: {num}')

gen = my_generator(3)
for num in gen:
    print(f'Generator: {num}')

