# Layihədə istifadə
class RangeIterator:
    def __init__(self, start, end):
        self.current = start
        self.end = end

    def __iter__(self):
        return self

    def __next__(self):
        if self.current < self.end:
            result = self.current
            self.current += 1
            return result
        raise StopIteration

range_iter = RangeIterator(1, 4)
for num in range_iter:
    print(num)

